-- Migration: Add External Agent Support to Messages Table
-- Date: 2025-11-03
-- Description: Adds support for tracking external agent (like Claude Code) messages
--              with session tracking and agent type identification

-- ============================================================================
-- STEP 1: Add new role type 'ex_agent' to message_role enum
-- ============================================================================

-- Add 'ex_agent' role to the existing message_role enum
-- This role identifies messages generated by external agents (like Claude Code)
-- Distinguished from 'assistant' which is for regular LLM responses

ALTER TYPE message_role ADD VALUE IF NOT EXISTS 'ex_agent';

-- ============================================================================
-- STEP 2: Add external agent tracking fields to messages table
-- ============================================================================

-- Add ex_agent_session_id column
-- This tracks which external agent session created the message
-- Enables session-based queries and conversation forking
-- NULL for non-agent messages (user, assistant, system)

ALTER TABLE messages
  ADD COLUMN IF NOT EXISTS ex_agent_session_id TEXT NULL;

-- Add ex_agent_type column
-- Specifies which type of external agent created the message
-- Values: 'claude_code', or other future agent types
-- NULL for non-agent messages

ALTER TABLE messages
  ADD COLUMN IF NOT EXISTS ex_agent_type TEXT NULL;

-- ============================================================================
-- STEP 3: Add index for efficient session-based queries
-- ============================================================================

-- Create partial index on ex_agent_session_id
-- Only indexes rows where ex_agent_session_id is not NULL (agent messages only)
-- Improves performance for:
--   - Finding all messages in a CC session
--   - Resuming conversations based on session ID
--   - Querying conversation history by agent

CREATE INDEX IF NOT EXISTS idx_messages_ex_agent_session
  ON messages(ex_agent_session_id)
  WHERE ex_agent_session_id IS NOT NULL;

-- ============================================================================
-- STEP 4: (Optional) Add working directory tracking to conversations
-- ============================================================================

-- Add cwd (current working directory) column to conversations table
-- Stores the working directory context for Claude Code sessions
-- Helps maintain proper file path resolution when resuming sessions
-- NULL for conversations that don't use Claude Code

ALTER TABLE conversations
  ADD COLUMN IF NOT EXISTS cwd TEXT NULL;

-- ============================================================================
-- STEP 5: Add composite index for conversation + session queries
-- ============================================================================

-- Create index for efficient queries that filter by both conversation and session
-- Useful for:
--   - Finding specific session messages within a conversation
--   - Conversation branching/forking scenarios
--   - Session-specific message retrieval

CREATE INDEX IF NOT EXISTS idx_messages_conv_session
  ON messages(conversation_id, ex_agent_session_id)
  WHERE ex_agent_session_id IS NOT NULL;

-- ============================================================================
-- VERIFICATION QUERIES
-- ============================================================================

