-- ============================================================================
-- ROLLBACK SCRIPT (for reference - run manually if needed)
-- ============================================================================

-- WARNING: This rollback will remove the enum value and columns
-- This should only be done if no data exists using the ex_agent role

-- DROP INDEX IF EXISTS idx_messages_conv_session;
-- DROP INDEX IF EXISTS idx_messages_ex_agent_session;
-- ALTER TABLE conversations DROP COLUMN IF EXISTS cwd;
-- ALTER TABLE messages DROP COLUMN IF EXISTS ex_agent_type;
-- ALTER TABLE messages DROP COLUMN IF EXISTS ex_agent_session_id;

-- Note: Removing enum values requires recreating the enum type:
-- 1. Create new enum without 'ex_agent'
-- 2. Alter table to use new enum
-- 3. Drop old enum
-- This is complex and should be avoided if any data uses the enum value

